@Keep
class ApiLoggingInterceptor(
    private val enabledProvider: () -> Boolean = { AppLogging.enabled },
    private val includeSensitiveProvider: () -> Boolean = { AppLogging.includeSensitive },
    private val maxBodyCharsProvider: () -> Int = { AppLogging.maxBodyChars }
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val enabled = enabledProvider()
        val includeSensitive = includeSensitiveProvider()
        val maxBodyChars = maxBodyCharsProvider()

        val request = chain.request()
        val startNs = System.nanoTime()

        if (enabled) {
            val reqLog = buildString {
                append("HTTP -> ")
                append(request.method)
                append(" ")
                append(request.url)
                append("\nHeaders:\n")
                append(formatHeaders(request, includeSensitive))
                append("\nBody:\n")
                append(readRequestBody(request, maxBodyChars, includeSensitive))
            }
            Timber.tag("API").v(reqLog)
        }

        val response: Response = try {
            chain.proceed(request)
        } catch (t: Throwable) {
            if (enabled) {
                Timber.tag("API").e(t, "HTTP !! exception ${request.method} ${request.url}")
            }
            throw t
        }

        val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)

        if (!enabled) return response

        val peeked = try {
            response.peekBody(maxBodyChars.toLong())
        } catch (_: Throwable) {
            null
        }

        val respLog = buildString {
            append("HTTP <- ")
            append(response.code)
            append(" ")
            append(response.message)
            append(" ")
            append(request.method)
            append(" ")
            append(request.url)
            append(" (")
            append(tookMs)
            append("ms)")
            append("\nHeaders:\n")
            append(formatHeaders(response, includeSensitive))
            append("\nBody:\n")
            append(readResponseBody(peeked, response.body?.contentType(), maxBodyChars))
        }

        when {
            response.code >= 500 -> Timber.tag("API").e(respLog)
            response.code >= 400 -> Timber.tag("API").w(respLog)
            tookMs >= 2000 -> Timber.tag("API").w(respLog)
            else -> Timber.tag("API").v(respLog)
        }

        return response
    }

    private fun formatHeaders(request: Request, includeSensitive: Boolean): String {
        val headers = request.headers
        if (headers.size == 0) return "(none)"
        val sb = StringBuilder()
        for (i in 0 until headers.size) {
            val name = headers.name(i)
            val value = headers.value(i)
            sb.append(name).append(": ").append(maskHeaderValue(name, value, includeSensitive)).append('\n')
        }
        return sb.toString().trimEnd()
    }

    private fun formatHeaders(response: Response, includeSensitive: Boolean): String {
        val headers = response.headers
        if (headers.size == 0) return "(none)"
        val sb = StringBuilder()
        for (i in 0 until headers.size) {
            val name = headers.name(i)
            val value = headers.value(i)
            sb.append(name).append(": ").append(maskHeaderValue(name, value, includeSensitive)).append('\n')
        }
        return sb.toString().trimEnd()
    }

    private fun maskHeaderValue(name: String, value: String, includeSensitive: Boolean): String {
        if (includeSensitive) return value
        val lower = name.lowercase(Locale.US)
        return when {
            lower == "authorization" -> "***"
            lower == "cookie" -> "***"
            lower == "set-cookie" -> "***"
            lower.startsWith("x-api-key") -> "***"
            lower.contains("token") -> "***"
            else -> value
        }
    }

    private fun readRequestBody(request: Request, maxChars: Int, includeSensitive: Boolean): String {
        val body = request.body ?: return "(no body)"
        val contentType = body.contentType()
        if (!isProbablyText(contentType)) return "(binary body ${contentType ?: "unknown"})"

        return try {
            val buffer = Buffer()
            val copy = bodyToCopy(body)
            copy.writeTo(buffer)
            val charset = contentType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            var text = buffer.readString(charset)
            if (!includeSensitive) {
                text = scrubCommonSecrets(text)
            }
            if (text.length > maxChars) text.take(maxChars) + "…(truncated ${text.length - maxChars} chars)" else text
        } catch (t: Throwable) {
            "(! failed to read request body: ${t.javaClass.simpleName}: ${t.message})"
        }
    }

    private fun bodyToCopy(body: RequestBody): RequestBody {
        return object : RequestBody() {
            override fun contentType(): MediaType? = body.contentType()
            override fun contentLength(): Long = try {
                body.contentLength()
            } catch (_: Throwable) {
                -1L
            }
            override fun writeTo(sink: okio.BufferedSink) = body.writeTo(sink)
        }
    }

    private fun readResponseBody(peeked: ResponseBody?, contentType: MediaType?, maxChars: Int): String {
        if (peeked == null) return "(unavailable)"
        if (!isProbablyText(contentType)) return "(binary body ${contentType ?: "unknown"})"
        return try {
            val charset: Charset = contentType?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
            val text = peeked.source().buffer.clone().readString(charset)
            if (text.length > maxChars) text.take(maxChars) + "…(truncated ${text.length - maxChars} chars)" else text
        } catch (t: Throwable) {
            "(! failed to read response body: ${t.javaClass.simpleName}: ${t.message})"
        }
    }

    private fun isProbablyText(mediaType: MediaType?): Boolean {
        if (mediaType == null) return true
        val type = mediaType.type.lowercase(Locale.US)
        val subtype = mediaType.subtype.lowercase(Locale.US)
        if (type == "text") return true
        if (subtype.contains("json")) return true
        if (subtype.contains("xml")) return true
        if (subtype.contains("html")) return true
        if (subtype.contains("x-www-form-urlencoded")) return true
        if (subtype.contains("graphql")) return true
        return false
    }

    private fun scrubCommonSecrets(text: String): String {
        var t = text
        val patterns = listOf(
            Regex("(?i)(\"password\"\\s*:\\s*\")([^\"]*)(\")"),
            Regex("(?i)(\"pass\"\\s*:\\s*\")([^\"]*)(\")"),
            Regex("(?i)(\"token\"\\s*:\\s*\")([^\"]*)(\")"),
            Regex("(?i)(\"access_token\"\\s*:\\s*\")([^\"]*)(\")"),
            Regex("(?i)(\"refresh_token\"\\s*:\\s*\")([^\"]*)(\")"),
            Regex("(?i)(\"api_key\"\\s*:\\s*\")([^\"]*)(\")"),
            Regex("(?i)(\"secret\"\\s*:\\s*\")([^\"]*)(\")")
        )
        for (r in patterns) {
            t = t.replace(r) { m -> m.groupValues[1] + "***" + m.groupValues[3] }
        }
        return t
    }
}

@Keep
object CrashLogging {

    @Volatile
    private var installed = false

    fun install() {
        if (installed) return
        installed = true
        val prev = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            try {
                AppLogging.exception(
                    throwable,
                    context = "UncaughtException thread=${thread.name}",
                    extra = mapOf(
                        "threadId" to thread.id,
                        "threadState" to thread.state.name
                    )
                )
            } catch (_: Throwable) {
            } finally {
                prev?.uncaughtException(thread, throwable)
            }
        }
    }
}

@Keep
object DbQueryLogger {
    fun logQuery(
        dbName: String,
        sql: String,
        args: List<Any?>? = null,
        durationMs: Long? = null,
        rows: Int? = null,
        throwable: Throwable? = null
    ) {
        AppLogging.dbQuery(
            dbName = dbName,
            sql = sql,
            args = args,
            durationMs = durationMs,
            rows = rows,
            throwable = throwable
        )
    }

    fun <T> measureAndLog(
        dbName: String,
        sql: String,
        args: List<Any?>? = null,
        block: () -> T
    ): T {
        val start = System.nanoTime()
        return try {
            val result = block()
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start)
            AppLogging.dbQuery(dbName, sql, args, durationMs = tookMs)
            result
        } catch (t: Throwable) {
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - start)
            AppLogging.dbQuery(dbName, sql, args, durationMs = tookMs, throwable = t)
            throw t
        }
    }
}

