@Keep
object ExceptionLogger {
    fun log(t: Throwable, context: String? = null, extra: Map<String, Any?> = emptyMap()) {
        AppLogging.exception(t, context, extra)
    }

    fun async(t: Throwable, context: String? = null, extra: Map<String, Any?> = emptyMap()) {
        if (!AppLogging.enabled) return
        val err = t
        AppLogging.raw("EXC", Log.VERBOSE, "Scheduling async exception log", null)
        try {
            val field = AppLogging::class.java.getDeclaredField("ioScope")
            field.isAccessible = true
            val scope = field.get(AppLogging) as CoroutineScope
            scope.launch {
                AppLogging.exception(err, context, extra)
            }
        } catch (_: Throwable) {
            AppLogging.exception(err, context, extra)
        }
    }
}